.darma-loader-darma-custom-669__spinner {color: var(--loader-color, #6366f1);

  position: relative;
  width: 9px;
  height: 9px;
}

.darma-loader-darma-custom-669__spinner div {
  position: absolute;
  width: 50%;
  height: 150%;
  background: var(--loader-color, #6366f1);
  transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1%));
  animation: darma-loader-darma-custom-669-spinner-fzua35 1s calc(var(--delay) * 1s) infinite ease;
}

.darma-loader-darma-custom-669__spinner div:nth-child(1) {
  --delay: 0.1;
  --rotation: 36;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(2) {
  --delay: 0.2;
  --rotation: 72;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(3) {
  --delay: 0.3;
  --rotation: 108;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(4) {
  --delay: 0.4;
  --rotation: 144;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(5) {
  --delay: 0.5;
  --rotation: 180;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(6) {
  --delay: 0.6;
  --rotation: 216;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(7) {
  --delay: 0.7;
  --rotation: 252;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(8) {
  --delay: 0.8;
  --rotation: 288;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(9) {
  --delay: 0.9;
  --rotation: 324;
  --translation: 150;
}

.darma-loader-darma-custom-669__spinner div:nth-child(10) {
  --delay: 1;
  --rotation: 360;
  --translation: 150;
}

@keyframes darma-loader-darma-custom-669-spinner-fzua35 {
  0%, 10%, 20%, 30%, 50%, 60%, 70%, 80%, 90%, 100% {
    transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1%));
  }

  50% {
    transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1.5%));
  }
}

